SELECT ?emperor ?label WHERE {
  wd:Q193547 wdt:P582 ?reignEnd .
  ?emperor p:P39 ?position .
  ?position ps:P39 wd:Q5373953 .
  ?position pq:P580 ?startTime .
  FILTER (?startTime > ?reignEnd)
  OPTIONAL { ?emperor rdfs:label ?label . FILTER (lang(?label) = "en") }
}

